module RAM
#(
    parameter WIDTH = 6,
    parameter DEPTH = 8
)
(
    input clk,
    input rst_n,
    input write_en,
    input [$clog2(DEPTH)-1:0] write_addr,
    input [WIDTH-1:0] write_data,
    input read_en,
    input [$clog2(DEPTH)-1:0] read_addr,
    output reg [WIDTH-1:0] read_data
);

    // Define the RAM array
    reg [WIDTH-1:0] RAM [DEPTH-1:0];

    // Initialize the RAM to all zeros
    integer i;
    initial begin
        for (i = 0; i < DEPTH; i = i + 1) begin
            RAM[i] = 0;
        end
    end

    // Write operation
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset the RAM to all zeros
            for (i = 0; i < DEPTH; i = i + 1) begin
                RAM[i] = 0;
            end
        end
        else if (write_en) begin
            // Write data to the RAM at the specified address
            RAM[write_addr] = write_data;
        end
    end

    // Read operation
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset read_data to all zeros
            read_data = 0;
        end
        else if (read_en) begin
            // Read data from the RAM at the specified address
            read_data = RAM[read_addr];
        end
        else begin
            // Reset read_data to all zeros when read_en is not 1
            read_data = 0;
        end
    end

endmodule
